# ==============================================================================
# Model Downloader
# ==============================================================================
class ModelDownloader:
    """Downloads and caches pretrained model checkpoints from URLs."""

    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.manifest_path = self.cache_dir / "manifest.json"
        self.manifest = self._load_manifest()

    def _load_manifest(self) -> Dict:
        """Load download manifest tracking cached models."""
        if self.manifest_path.exists():
            with open(self.manifest_path, "r") as f:
                return json.load(f)
        return {}

    def _save_manifest(self):
        """Save download manifest."""
        with open(self.manifest_path, "w") as f:
            json.dump(self.manifest, f, indent=2)

    def _compute_checksum(self, filepath: str) -> str:
        """Compute SHA256 checksum of a file."""
        sha256 = hashlib.sha256()
        with open(filepath, "rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                sha256.update(chunk)
        return sha256.hexdigest()

    def download_model(self, model_name: str, force: bool = False) -> str:
        """
        Download a pretrained model checkpoint from URL.

        Args:
            model_name: Name of the model in MODEL_REGISTRY
            force: Force re-download even if cached

        Returns:
            Path to the downloaded checkpoint file
        """
        if model_name not in MODEL_REGISTRY:
            available = list(MODEL_REGISTRY.keys())
            raise ValueError(
                f"Model '{model_name}' not found. Available models: {available}"
            )

        model_info = MODEL_REGISTRY[model_name]
        url = model_info["url"]
        filename = f"{model_name}_pretrained.pth"
        filepath = self.cache_dir / filename

        # Check if already cached
        if not force and filepath.exists() and model_name in self.manifest:
            logger.info(f"Model '{model_name}' found in cache: {filepath}")
            return str(filepath)

        # Download the model
        logger.info(f"Downloading '{model_name}' from {url}...")
        try:
            urllib.request.urlretrieve(url, str(filepath), reporthook=self._progress_hook)
            print()  # New line after progress
        except Exception as e:
            logger.error(f"Failed to download model: {e}")
            raise

        # Compute checksum and update manifest
        checksum = self._compute_checksum(str(filepath))
        self.manifest[model_name] = {
            "url": url,
            "filepath": str(filepath),
            "checksum": checksum,
            "filename": filename,
        }
        self._save_manifest()

        logger.info(f"Model '{model_name}' downloaded successfully to {filepath}")
        logger.info(f"Checksum (SHA256): {checksum}")
        return str(filepath)

    def download_from_url(self, url: str, model_name: str) -> str:
        """
        Download a model checkpoint from an arbitrary URL.

        Args:
            url: URL to download from
            model_name: Name to assign to this model

        Returns:
            Path to the downloaded checkpoint file
        """
        filename = f"{model_name}_custom.pth"
        filepath = self.cache_dir / filename

        logger.info(f"Downloading custom model from {url}...")
        try:
            urllib.request.urlretrieve(url, str(filepath), reporthook=self._progress_hook)
            print()
        except Exception as e:
            logger.error(f"Failed to download: {e}")
            raise

        checksum = self._compute_checksum(str(filepath))
        self.manifest[model_name] = {
            "url": url,
            "filepath": str(filepath),
            "checksum": checksum,
            "filename": filename,
        }
        self._save_manifest()

        logger.info(f"Custom model downloaded to {filepath}")
        return str(filepath)

    @staticmethod
    def _progress_hook(block_num, block_size, total_size):
        """Progress hook for download."""
        downloaded = block_num * block_size
        if total_size > 0:
            percent = min(100, downloaded * 100 / total_size)
            mb_downloaded = downloaded / (1024 * 1024)
            mb_total = total_size / (1024 * 1024)
            print(
                f"\rProgress: {percent:.1f}% ({mb_downloaded:.1f}/{mb_total:.1f} MB)",
                end="",
                flush=True,
            )

    def load_checkpoint(self, model_name: str, map_location: str = "cpu") -> Dict:
        """
        Load a model checkpoint using torch.load.

        Args:
            model_name: Name of the model to load
            map_location: Device to map the checkpoint to

        Returns:
            Loaded checkpoint dictionary (state_dict)
        """
        filepath = self.download_model(model_name)
        logger.info(f"Loading checkpoint from {filepath}...")

        checkpoint = torch.load(filepath, map_location=map_location, weights_only=False)

        # Handle different checkpoint formats
        if isinstance(checkpoint, dict):
            if "state_dict" in checkpoint:
                state_dict = checkpoint["state_dict"]
            elif "model_state_dict" in checkpoint:
                state_dict = checkpoint["model_state_dict"]
            else:
                state_dict = checkpoint
        else:
            state_dict = checkpoint

        logger.info(f"Checkpoint loaded with {len(state_dict)} parameter tensors")
        return state_dict

    def list_cached_models(self) -> List[str]:
        """List all cached model names."""
        return list(self.manifest.keys())

    def clear_cache(self):
        """Clear all cached models."""
        import shutil
        shutil.rmtree(self.cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.manifest = {}
        self._save_manifest()
        logger.info("Model cache cleared")


