class CustomImageDataset(Dataset):
    """
    Custom dataset for fine-tuning.
    Supports loading images from directories organized by class.
    """

    def __init__(
        self,
        root_dir: str,
        transform: Optional[transforms.Compose] = None,
        class_names: Optional[List[str]] = None,
    ):
        self.root_dir = Path(root_dir)
        self.transform = transform
        self.samples = []
        self.class_to_idx = {}

        if self.root_dir.exists():
            # Load from directory structure: root/class_name/image.jpg
            if class_names is None:
                class_names = sorted(
                    [d.name for d in self.root_dir.iterdir() if d.is_dir()]
                )
            self.class_to_idx = {name: idx for idx, name in enumerate(class_names)}

            for class_name, idx in self.class_to_idx.items():
                class_dir = self.root_dir / class_name
                if class_dir.exists():
                    for img_path in class_dir.glob("*"):
                        if img_path.suffix.lower() in [
                            ".jpg", ".jpeg", ".png", ".bmp", ".tiff"
                        ]:
                            self.samples.append((str(img_path), idx))

            logger.info(
                f"Loaded {len(self.samples)} images across "
                f"{len(self.class_to_idx)} classes"
            )

    def __len__(self):
        return len(self.samples)

    def __getitem__(self, idx):
        img_path, label = self.samples[idx]
        image = Image.open(img_path).convert("RGB")
        if self.transform:
            image = self.transform(image)
        return image, label

    @property
    def num_classes(self):
        return len(self.class_to_idx)


class SyntheticDataset(Dataset):
    """Synthetic dataset for demonstration and testing purposes."""

    def __init__(
        self,
        num_samples: int = 1000,
        num_classes: int = 10,
        image_size: int = 224,
        channels: int = 3,
    ):
        self.num_samples = num_samples
        self.num_classes = num_classes
        self.image_size = image_size
        self.channels = channels

        # Generate synthetic data
        self.images = torch.randn(num_samples, channels, image_size, image_size)
        self.labels = torch.randint(0, num_classes, (num_samples,))

        logger.info(
            f"Created synthetic dataset: {num_samples} samples, "
            f"{num_classes} classes, {image_size}x{image_size}"
        )

    def __len__(self):
        return self.num_samples

    def __getitem__(self, idx):
        return self.images[idx], self.labels[idx]


