class TransferLearningPipeline:
    """
    Complete transfer learning pipeline for downloading pretrained models
    and fine-tuning them on custom datasets.
    """

    def __init__(
        self,
        model_name: str,
        num_classes: int,
        cache_dir: str = "./model_cache",
        device: Optional[str] = None,
        freeze_strategy: str = "feature_extractor",
    ):
        """
        Initialize the transfer learning pipeline.

        Args:
            model_name: Name of the pretrained model to use
            num_classes: Number of output classes for fine-tuning
            cache_dir: Directory to cache downloaded models
            device: Device to use (auto-detected if None)
            freeze_strategy: One of 'feature_extractor', 'partial_freeze', 'full_finetune'
        """
        self.model_name = model_name
        self.num_classes = num_classes
        self.freeze_strategy = freeze_strategy
        self.downloader = ModelDownloader(cache_dir)

        # Auto-detect device
        if device is None:
            self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
        else:
            self.device = torch.device(device)
        logger.info(f"Using device: {self.device}")

        # Training history
        self.history = {
            "train_loss": [],
            "train_acc": [],
            "val_loss": [],
            "val_acc": [],
        }

        # Build model
        self.model = self._build_model()

    def _build_model(self) -> nn.Module:
        """Build model architecture and load pretrained weights."""
        model_info = MODEL_REGISTRY[self.model_name]
        model_class = model_info["model_class"]

        # Create model architecture (without pretrained weights initially)
        logger.info(f"Building {model_class} architecture...")
        model = getattr(models, model_class)(weights=None)

        # Download and load pretrained weights
        state_dict = self.downloader.load_checkpoint(self.model_name)

        # Load state dict (handle potential mismatches)
        try:
            model.load_state_dict(state_dict, strict=True)
            logger.info("Pretrained weights loaded successfully (strict)")
        except RuntimeError as e:
            logger.warning(f"Strict loading failed: {e}")
            logger.info("Attempting partial loading...")
            model_state = model.state_dict()
            pretrained_state = {
                k: v for k, v in state_dict.items()
                if k in model_state and v.shape == model_state[k].shape
            }
            model_state.update(pretrained_state)
            model.load_state_dict(model_state)
            logger.info(
                f"Loaded {len(pretrained_state)}/{len(model_state)} "
                f"pretrained parameters"
            )

        # Modify classifier head for new number of classes
        model = self._replace_classifier(model, model_info)

        # Apply freezing strategy
        self._apply_freeze_strategy(model)

        model = model.to(self.device)

        # Log model statistics
        total_params = sum(p.numel() for p in model.parameters())
        trainable_params = sum(p.numel() for p in model.parameters() if p.requires_grad)
        logger.info(f"Total parameters: {total_params:,}")
        logger.info(f"Trainable parameters: {trainable_params:,}")
        logger.info(
            f"Frozen parameters: {total_params - trainable_params:,}"
        )

        return model

    def _replace_classifier(self, model: nn.Module, model_info: Dict) -> nn.Module:
        """Replace the classifier head for the target number of classes."""
        num_features = model_info["num_features"]
        model_class = model_info["model_class"]

        if "resnet" in model_class or "efficientnet" in model_class:
            # ResNet and EfficientNet use model.fc
            if hasattr(model, "fc"):
                model.fc = nn.Sequential(
                    nn.Dropout(0.3),
                    nn.Linear(num_features, 256),
                    nn.ReLU(),
                    nn.Dropout(0.2),
                    nn.Linear(256, self.num_classes),
                )
            # EfficientNet uses model.classifier
            elif hasattr(model, "classifier"):
                if isinstance(model.classifier, nn.Sequential):
                    in_features = model.classifier[-1].in_features
                    model.classifier[-1] = nn.Linear(in_features, self.num_classes)
                else:
                    model.classifier = nn.Sequential(
                        nn.Dropout(0.3),
                        nn.Linear(num_features, self.num_classes),
                    )
        elif "vgg" in model_class:
            model.classifier[-1] = nn.Linear(4096, self.num_classes)
        elif "mobilenet" in model_class:
            if hasattr(model, "classifier"):
                if isinstance(model.classifier, nn.Sequential):
                    in_features = model.classifier[-1].in_features
                    model.classifier[-1] = nn.Linear(in_features, self.num_classes)
                else:
                    model.classifier = nn.Sequential(
                        nn.Dropout(0.2),
                        nn.Linear(num_features, self.num_classes),
                    )

        logger.info(
            f"Replaced classifier head: {num_features} -> {self.num_classes} classes"
        )
        return model

    def _apply_freeze_strategy(self, model: nn.Module):
        """Apply parameter freezing strategy."""
        if self.freeze_strategy == "feature_extractor":
            # Freeze all layers except the classifier
            for param in model.parameters():
                param.requires_grad = False

            # Unfreeze classifier layers
            classifier_modules = self._get_classifier_modules(model)
            for module in classifier_modules:
                for param in module.parameters():
                    param.requires_grad = True

            logger.info("Strategy: Feature extractor (only classifier is trainable)")

        elif self.freeze_strategy == "partial_freeze":
            # Freeze early layers, unfreeze later layers + classifier
            all_children = list(model.children())
            freeze_until = len(all_children) * 2 // 3  # Freeze first 2/3

            for i, child in enumerate(all_children):
                if i < freeze_until:
                    for param in child.parameters():
                        param.requires_grad = False
                else:
                    for param in child.parameters():
                        param.requires_grad = True

            logger.info(
                f"Strategy: Partial freeze (frozen first {freeze_until} "
                f"of {len(all_children)} layer groups)"
            )

        elif self.freeze_strategy == "full_finetune":
            # All parameters are trainable
            for param in model.parameters():
                param.requires_grad = True
            logger.info("Strategy: Full fine-tune (all parameters trainable)")

        else:
            raise ValueError(
                f"Unknown freeze strategy: {self.freeze_strategy}. "
                f"Choose from: feature_extractor, partial_freeze, full_finetune"
            )

    def _get_classifier_modules(self, model: nn.Module) -> List[nn.Module]:
        """Get classifier modules based on model architecture."""
        modules = []
        if hasattr(model, "fc"):
            modules.append(model.fc)
        if hasattr(model, "classifier"):
            modules.append(model.classifier)
        return modules

    def get_data_transforms(self, image_size: int = 224) -> Dict[str, transforms.Compose]:
        """Get data transforms for training and validation."""
        normalize = transforms.Normalize(
            mean=[0.485, 0.456, 0.406],
            std=[0.229, 0.224, 0.225],
        )

        return {
            "train": transforms.Compose([
                transforms.RandomResizedCrop(image_size),
                transforms.RandomHorizontalFlip(),
                transforms.RandomRotation(15),
                transforms.ColorJitter(
                    brightness=0.2, contrast=0.2, saturation=0.2, hue=0.1
                ),
                transforms.ToTensor(),
                normalize,
            ]),
            "val": transforms.Compose([
                transforms.Resize(image_size + 32),
                transforms.CenterCrop(image_size),
                transforms.ToTensor(),
                normalize,
            ]),
        }

    def prepare_dataloaders(
        self,
        dataset: Dataset,
        batch_size: int = 32,
        val_split: float = 0.2,
        num_workers: int = 2,
    ) -> Tuple[DataLoader, DataLoader]:
        """
        Prepare training and validation dataloaders.

        Args:
            dataset: The dataset to split
            batch_size: Batch size for training
            val_split: Fraction of data for validation
            num_workers: Number of data loading workers

        Returns:
            Tuple of (train_loader, val_loader)
        """
        total = len(dataset)
        val_size = int(total * val_split)
        train_size = total - val_size

        train_dataset, val_dataset = random_split(
            dataset,
            [train_size, val_size],
            generator=torch.Generator().manual_seed(42),
        )

        train_loader = DataLoader(
            train_dataset,
            batch_size=batch_size,
            shuffle=True,
            num_workers=num_workers,
            pin_memory=True if self.device.type == "cuda" else False,
        )

        val_loader = DataLoader(
            val_dataset,
            batch_size=batch_size,
            shuffle=False,
            num_workers=num_workers,
            pin_memory=True if self.device.type == "cuda" else False,
        )

        logger.info(
            f"Data split: {train_size} training, {val_size} validation samples"
        )
        return train_loader, val_loader

    def train(
        self,
        train_loader: DataLoader,
        val_loader: DataLoader,
        num_epochs: int = 10,
        learning_rate: float = 0.001,
        weight_decay: float = 1e-4,
        scheduler_step_size: int = 7,
        scheduler_gamma: float = 0.1,
        early_stopping_patience: int = 5,
        save_best: bool = True,
        save_path: str = "./best_model.pth",
    ) -> Dict:
        """
        Fine-tune the model on the provided data.

        Args:
            train_loader: Training data loader
            val_loader: Validation data loader
            num_epochs: Number of training epochs
            learning_rate: Initial learning rate
            weight_decay: L2 regularization weight
            scheduler_step_size: LR scheduler step size
            scheduler_gamma: LR scheduler decay factor
            early_stopping_patience: Epochs to wait before early stopping
            save_best: Whether to save the best model
            save_path: Path to save the best model

        Returns:
            Training history dictionary
        """
        # Setup loss, optimizer, and scheduler
        criterion = nn.CrossEntropyLoss()

        # Different learning rates for different parts of the model
        param_groups = self._get_param_groups(learning_rate)
        optimizer = optim.Adam(param_groups, weight_decay=weight_decay)

        scheduler = optim.lr_scheduler.StepLR(
            optimizer, step_size=scheduler_step_size, gamma=scheduler_gamma
        )

        best_val_acc = 0.0
        patience_counter = 0
        best_model_state = None

        logger.info(f"Starting fine-tuning for {num_epochs} epochs...")
        logger.info(f"Learning rate: {learning_rate}, Weight decay: {weight_decay}")

        for epoch in range(num_epochs):
            # Training phase
            train_loss, train_acc = self._train_epoch(
                train_loader, criterion, optimizer
            )

            # Validation phase
            val_loss, val_acc = self._validate(val_loader, criterion)

            # Update scheduler
            scheduler.step()

            # Record history
            self.history["train_loss"].append(train_loss)
            self.history["train_acc"].append(train_acc)
            self.history["val_loss"].append(val_loss)
            self.history["val_acc"].append(val_acc)

            # Get current LR
            current_lr = optimizer.param_groups[0]["lr"]

            logger.info(
                f"Epoch [{epoch + 1}/{num_epochs}] "
                f"Train Loss: {train_loss:.4f}, Train Acc: {train_acc:.4f} | "
                f"Val Loss: {val_loss:.4f}, Val Acc: {val_acc:.4f} | "
                f"LR: {current_lr:.6f}"
            )

            # Save best model
            if val_acc > best_val_acc:
                best_val_acc = val_acc
                patience_counter = 0
                best_model_state = {
                    k: v.clone() for k, v in self.model.state_dict().items()
                }
                if save_best:
                    self.save_model(save_path, epoch, optimizer, val_acc, val_loss)
                    logger.info(
                        f"  *** New best model saved (Val Acc: {val_acc:.4f}) ***"
                    )
            else:
                patience_counter += 1

            # Early stopping
            if patience_counter >= early_stopping_patience:
                logger.info(
                    f"Early stopping triggered after {epoch + 1} epochs "
                    f"(no improvement for {early_stopping_patience} epochs)"
                )
                break

        # Load best model weights
        if best_model_state is not None:
            self.model.load_state_dict(best_model_state)
            logger.info(f"Loaded best model weights (Val Acc: {best_val_acc:.4f})")

        return self.history

    def _get_param_groups(self, base_lr: float) -> List[Dict]:
        """Create parameter groups with differential learning rates."""
        classifier_params = []
        backbone_params = []

        classifier_modules = self._get_classifier_modules(self.model)
        classifier_param_ids = set()
        for module in classifier_modules:
            for param in module.parameters():
                if param.requires_grad:
                    classifier_params.append(param)
                    classifier_param_ids.add(id(param))

        for param in self.model.parameters():
            if param.requires_grad and id(param) not in classifier_param_ids:
                backbone_params.append(param)

        param_groups = []
        if backbone_params:
            param_groups.append({"params": backbone_params, "lr": base_lr * 0.1})
        if classifier_params:
            param_groups.append({"params": classifier_params, "lr": base_lr})

        if not param_groups:
            # Fallback: all trainable params
            param_groups = [
                {"params": [p for p in self.model.parameters() if p.requires_grad],
                 "lr": base_lr}
            ]

        return param_groups

    def _train_epoch(
        self,
        train_loader: DataLoader,
        criterion: nn.Module,
        optimizer: optim.Optimizer,
    ) -> Tuple[float, float]:
        """Run one training epoch."""
        self.model.train()
        running_loss = 0.0
        correct = 0
        total = 0

        for batch_idx, (inputs, labels) in enumerate(train_loader):
            inputs = inputs.to(self.device)
            labels = labels.to(self.device)

            optimizer.zero_grad()
            outputs = self.model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()

            # Gradient clipping
            torch.nn.utils.clip_grad_norm_(self.model.parameters(), max_norm=1.0)

            optimizer.step()

            running_loss += loss.item() * inputs.size(0)
            _, predicted = outputs.max(1)
            total += labels.size(0)
            correct += predicted.eq(labels).sum().item()

        epoch_loss = running_loss / total
        epoch_acc = correct / total
        return epoch_loss, epoch_acc

    @torch.no_grad()
    def _validate(
        self, val_loader: DataLoader, criterion: nn.Module
    ) -> Tuple[float, float]:
        """Run validation."""
        self.model.eval()
        running_loss = 0.0
        correct = 0
        total = 0

        for inputs, labels in val_loader:
            inputs = inputs.to(self.device)
            labels = labels.to(self.device)

            outputs = self.model(inputs)
            loss = criterion(outputs, labels)

            running_loss += loss.item() * inputs.size(0)
            _, predicted = outputs.max(1)
            total += labels.size(0)
            correct += predicted.eq(labels).sum().item()

        epoch_loss = running_loss / total
        epoch_acc = correct / total
        return epoch_loss, epoch_acc

    @torch.no_grad()
    def predict(self, inputs: torch.Tensor) -> Tuple[torch.Tensor, torch.Tensor]:
        """
        Run inference on input tensor.

        Args:
            inputs: Input tensor of shape (batch, channels, height, width)

        Returns:
            Tuple of (predicted_classes, probabilities)
        """
        self.model.eval()
        inputs = inputs.to(self.device)
        outputs = self.model(inputs)
        probabilities = torch.softmax(outputs, dim=1)
        predicted_classes = probabilities.argmax(dim=1)
        return predicted_classes, probabilities

    def save_model(
        self,
        path: str,
        epoch: int = 0,
        optimizer: Optional[optim.Optimizer] = None,
        val_acc: float = 0.0,
        val_loss: float = 0.0,
    ):
        """Save model checkpoint."""
        checkpoint = {
            "epoch": epoch,
            "model_name": self.model_name,
            "num_classes": self.num_classes,
            "freeze_strategy": self.freeze_strategy,
            "model_state_dict": self.model.state_dict(),
            "val_acc": val_acc,
            "val_loss": val_loss,
            "history": self.history,
        }
        if optimizer is not None:
            checkpoint["optimizer_state_dict"] = optimizer.state_dict()

        Path(path).parent.mkdir(parents=True, exist_ok=True)
        torch.save(checkpoint, path)
        logger.info(f"Model saved to {path}")

    def load_model(self, path: str):
        """Load a saved model checkpoint."""
        checkpoint = torch.load(path, map_location=self.device, weights_only=False)

        self.model.load_state_dict(checkpoint["model_state_dict"])
        self.history = checkpoint.get("history", self.history)

        logger.info(
            f"Model loaded from {path} "
            f"(Epoch: {checkpoint.get('epoch', 'N/A')}, "
            f"Val Acc: {checkpoint.get('val_acc', 'N/A')})"
        )
        return checkpoint

    def unfreeze_layers(self, num_layers: int = -1):
        """
        Gradually unfreeze layers for progressive fine-tuning.

        Args:
            num_layers: Number of layer groups to unfreeze from the end.
                       -1 means unfreeze all.
        """
        all_children = list(self.model.children())

        if num_layers == -1:
            for param in self.model.parameters():
                param.requires_grad = True
            logger.info("All layers unfrozen")
        else:
            start_idx = max(0, len(all_children) - num_layers)
            for i, child in enumerate(all_children):
                if i >= start_idx:
                    for param in child.parameters():
                        param.requires_grad = True

            trainable = sum(
                p.numel() for p in self.model.parameters() if p.requires_grad
            )
            total = sum(p.numel() for p in self.model.parameters())
            logger.info(
                f"Unfrozen last {num_layers} layer groups. "
                f"Trainable: {trainable:,}/{total:,}"
            )

    def evaluate(self, test_loader: DataLoader) -> Dict:
        """
        Evaluate model on test data.

        Returns:
            Dictionary with evaluation metrics
        """
        self.model.eval()
        criterion = nn.CrossEntropyLoss()

        all_preds = []
        all_labels = []
        running_loss = 0.0
        total = 0

        with torch.no_grad():
            for inputs, labels in test_loader:
                inputs = inputs.to(self.device)
                labels = labels.to(self.device)

                outputs = self.model(inputs)
                loss = criterion(outputs, labels)

                running_loss += loss.item() * inputs.size(0)
                _, predicted = outputs.max(1)
                total += labels.size(0)

                all_preds.extend(predicted.cpu().numpy())
                all_labels.extend(labels.cpu().numpy())

        all_preds = np.array(all_preds)
        all_labels = np.array(all_labels)

        accuracy = (all_preds == all_labels).mean()
        avg_loss = running_loss / total

        # Per-class accuracy
        unique_classes = np.unique(all_labels)
        per_class_acc = {}
        for cls in unique_classes:
            mask = all_labels == cls
            per_class_acc[int(cls)] = (all_preds[mask] == all_labels[mask]).mean()

        results = {
            "accuracy": float(accuracy),
            "loss": float(avg_loss),
            "per_class_accuracy": per_class_acc,
            "num_samples": total,
        }

        logger.info(f"Evaluation Results:")
        logger.info(f"  Overall Accuracy: {accuracy:.4f}")
        logger.info(f"  Average Loss: {avg_loss:.4f}")
        for cls, acc in per_class_acc.items():
            logger.info(f"  Class {cls} Accuracy: {acc:.4f}")

        return results


