def quick_transfer_learn(
    model_name: str = "resnet18",
    num_classes: int = 10,
    dataset: Optional[Dataset] = None,
    num_epochs: int = 10,
    batch_size: int = 32,
    learning_rate: float = 0.001,
    freeze_strategy: str = "feature_extractor",
    save_path: str = "./finetuned_model.pth",
) -> Tuple[TransferLearningPipeline, Dict]:
    """
    Quick transfer learning with minimal configuration.

    Args:
        model_name: Pretrained model to use
        num_classes: Number of target classes
        dataset: Dataset to fine-tune on (uses synthetic if None)
        num_epochs: Number of training epochs
        batch_size: Batch size
        learning_rate: Learning rate
        freeze_strategy: Freezing strategy
        save_path: Where to save the best model

    Returns:
        Tuple of (pipeline, training_history)
    """
    # Create pipeline
    pipeline = TransferLearningPipeline(
        model_name=model_name,
        num_classes=num_classes,
        freeze_strategy=freeze_strategy,
    )

    # Use synthetic data if no dataset provided
    if dataset is None:
        logger.info("No dataset provided, using synthetic data for demonstration")
        dataset = SyntheticDataset(
            num_samples=500,
            num_classes=num_classes,
            image_size=224,
        )

    # Prepare data loaders
    train_loader, val_loader = pipeline.prepare_dataloaders(
        dataset, batch_size=batch_size
    )

    # Train
    history = pipeline.train(
        train_loader=train_loader,
        val_loader=val_loader,
        num_epochs=num_epochs,
        learning_rate=learning_rate,
        save_best=True,
        save_path=save_path,
    )

    return pipeline, history


