# Main Demonstration
# ==============================================================================
def main():
    """Main demonstration of the transfer learning pipeline."""

    print("\n" + "=" * 70)
    print("Transfer Learning Pipeline - Demo")
    print("=" * 70 + "\n")

    # 1. List available models
    list_available_models()

    # 2. Initialize the downloader
    downloader = ModelDownloader(cache_dir="./model_cache")

    # 3. Download a pretrained model
    model_name = "resnet18"
    logger.info(f"Step 1: Downloading pretrained {model_name}...")
    checkpoint_path = downloader.download_model(model_name)

    # 4. Load checkpoint
    logger.info(f"Step 2: Loading checkpoint...")
    state_dict = downloader.load_checkpoint(model_name)
    logger.info(f"Loaded {len(state_dict)} parameter tensors from checkpoint")

    # 5. Create synthetic dataset for demo
    logger.info("Step 3: Creating synthetic dataset...")
    num_classes = 5
    dataset = SyntheticDataset(
        num_samples=200,  # Small for demo
        num_classes=num_classes,
        image_size=224,
    )

    # 6. Setup transfer learning pipeline
    logger.info("Step 4: Setting up transfer learning pipeline...")

    # Strategy 1: Feature extractor (fastest)
    pipeline = TransferLearningPipeline(
        model_name=model_name,
        num_classes=num_classes,
        freeze_strategy="feature_extractor",
    )

    # 7. Prepare data loaders
    train_loader, val_loader = pipeline.prepare_dataloaders(
        dataset, batch_size=16, val_split=0.2
    )

    # 8. Fine-tune the model
    logger.info("Step 5: Fine-tuning model...")
    history = pipeline.train(
        train_loader=train_loader,
        val_loader=val_loader,
        num_epochs=3,  # Few epochs for demo
        learning_rate=0.001,
        early_stopping_patience=5,
        save_best=True,
        save_path="./outputs/best_model.pth",
    )

    # 9. Evaluate
    logger.info("Step 6: Evaluating model...")
    eval_results = pipeline.evaluate(val_loader)

    # 10. Progressive fine-tuning demo
    logger.info("Step 7: Progressive fine-tuning (unfreezing layers)...")
    pipeline.unfreeze_layers(num_layers=2)

    # Continue training with lower learning rate
    history_progressive = pipeline.train(
        train_loader=train_loader,
        val_loader=val_loader,
        num_epochs=2,
        learning_rate=0.0001,  # Lower LR for unfrozen layers
        save_best=True,
        save_path="./outputs/best_model_progressive.pth",
    )

    # 11. Run inference
    logger.info("Step 8: Running inference...")
    sample_input = torch.randn(4, 3, 224, 224)
    predictions, probabilities = pipeline.predict(sample_input)
    logger.info(f"Predictions: {predictions.cpu().numpy()}")
    logger.info(f"Confidence: {probabilities.max(dim=1)[0].cpu().numpy()}")

    # 12. Save final model
    pipeline.save_model(
        "./outputs/final_model.pth",
        epoch=5,
        val_acc=eval_results["accuracy"],
    )

    # 13. Show cached models
    cached = downloader.list_cached_models()
    logger.info(f"Cached models: {cached}")

    print("\n" + "=" * 70)
    print("Transfer Learning Pipeline - Demo Complete!")
    print("=" * 70)
    print(f"\nFinal Evaluation Accuracy: {eval_results['accuracy']:.4f}")
    print(f"Models cached in: ./model_cache/")
    print(f"Best model saved to: ./outputs/best_model.pth")
    print("=" * 70 + "\n")

    return pipeline, history, eval_results


if __name__ == "__main__":
    main()